args.command:
python3 << 'EOF'
import eccodes
import sys

file_path = "/tmp/gribtract_fixtures/nam_alaska_f000.grib2"

with open(file_path, "rb") as f:
    try:
        msg = eccodes.codes_grib_new_from_file(f)
        if msg:
            try:
                gdt = eccodes.codes_get(msg, "gridDefinitionTemplateNumber")
            except:
                gdt = -1
            try:
                drt = eccodes.codes_get(msg, "dataRepresentationTemplateNumber")
            except:
                drt = -1
            try:
                pdt = eccodes.codes_get(msg, "productDefinitionTemplateNumber")
            except:
                pdt = -1
            try:
                grid_type = eccodes.codes_get(msg, "gridType")
            except:
                grid_type = "unknown"
            try:
                name = eccodes.codes_get(msg, "name")
            except:
                name = "unknown"
            try:
                short_name = eccodes.codes_get(msg, "shortName")
            except:
                short_name = "unknown"
            try:
                ni = eccodes.codes_get(msg, "Ni")
            except:
                ni = -1
            try:
                nj = eccodes.codes_get(msg, "Nj")
            except:
                nj = -1

            print(f"Grid Type: {grid_type}")
            print(f"GDT: {gdt}")
            print(f"DRT: {drt}")
            print(f"PDT: {pdt}")
            print(f"Parameter: {name} ({short_name})")
            print(f"Grid size: {ni} x {nj}")

            eccodes.codes_release(msg)
            print("\nFirst message inspection successful!")
        else:
            print("Failed to read GRIB2 message")
            sys.exit(1)
    except Exception as e:
        print(f"Error: {e}")
        import traceback
        traceback.print_exc()
        sys.exit(1)
EOF
